以文件 MD5 作为文件名（保留扩展名），递归处理子文件夹， 并生成一个 md5_rename_map.csv 记录原始文件名与改后文件名及MD5
``` import os import csv import hashlib from pathlib import Path
# ======== 可修改配置 ======== ROOT_DIR = Path(r'C:\test\md') # 要处理的目录 OUTPUT_CSV = ROOT_DIR / 'md5_rename_map1025.csv' # 输出映射表路径 DRY_RUN = False # True 仅预览不执行重命名 # ===========================
def md5_of_file(file_path, chunk_size=8192): '''计算文件 MD5''' md5 = hashlib.md5() with open(file_path, 'rb') as f: while chunk := f.read(chunk_size): md5.update(chunk) return md5.hexdigest()
def rename_file_to_md5(file_path: Path, writer): '''重命名单个文件为md5，并写入CSV''' try: md5_val = md5_of_file(file_path) new_name = f'{md5_val}{file_path.suffix.lower()}' new_path = file_path.with_name(new_name)
if new_path == file_path: # 已经是 md5 命名 return
if new_path.exists(): print(f'⚠️ 已存在相同MD5文件，跳过：{file_path}') return
if DRY_RUN: print(f'[DRY] {file_path} -> {new_path}') else: file_path.rename(new_path) print(f'✅ {file_path} -> {new_path}')
# 写入映射表 writer.writerow([str(file_path), str(new_path), md5_val])
except Exception as e: print(f'❌ {file_path} 计算或重命名失败：{e}')
def main(): with open(OUTPUT_CSV, 'w', newline='', encoding='utf-8') as f: writer = csv.writer(f) writer.writerow(['original_path', 'new_path', 'md5'])
for file in ROOT_DIR.rglob('*'): if file.is_file(): rename_file_to_md5(file, writer)
print(f'\n📄 映射表已生成：{OUTPUT_CSV}')
if __name__ == '__main__': main() ```。

# 部署 Gitea ``` #!/bin/bash # Gitea 管理脚本：安装前先卸载旧的 set -e
GITEA_VERSION='1.22.3' # 要安装的版本 GITEA_BIN='/usr/local/bin/gitea' GITEA_USER='git' GITEA_HOME='/var/lib/gitea' GITEA_CONF='/etc/gitea' SERVICE_FILE='/etc/systemd/system/gitea.service'
uninstall_gitea() { echo '⚠️ 卸载旧版 Gitea ...' systemctl stop gitea >/dev/null 2>&1 || true systemctl disable gitea >/dev/null 2>&1 || true rm -f $SERVICE_FILE rm -f $GITEA_BIN systemctl daemon-reload echo '✅ 卸载完成（数据目录 $GITEA_HOME 和配置 $GITEA_CONF 保留）' }
install_gitea() { echo '📥 开始安装 Gitea v${GITEA_VERSION} ...' # 卸载旧版本 uninstall_gitea
# 创建用户和目录 id -u $GITEA_USER &>/dev/null || useradd -r -m -d $GITEA_HOME -s /bin/bash $GITEA_USER mkdir -p $GITEA_HOME/{custom,data,log} $GITEA_CONF chown -R $GITEA_USER:$GITEA_USER $GITEA_HOME $GITEA_CONF
# 下载二进制 wget -O $GITEA_BIN 'https://dl.gitea.com/gitea/${GITEA_VERSION}/gitea-${GITEA_VERSION}-linux-amd64' chmod +x $GITEA_BIN
# 写 systemd 服务 cat > $SERVICE_FILE <<EOF [Unit] Description=Gitea After=syslog.target After=network.target Requires=network.target
[Service] RestartSec=2s Type=simple User=$GITEA_USER Group=$GITEA_USER WorkingDirectory=$GITEA_HOME ExecStart=$GITEA_BIN web --config $GITEA_CONF/app.ini Restart=always Environment=USER=$GITEA_USER HOME=$GITEA_HOME GITEA_WORK_DIR=$GITEA_HOME
[Install] WantedBy=multi-user.target EOF
systemctl daemon-reload systemctl enable gitea systemctl start gitea echo '✅ 安装完成！访问 http://你的IP:3000 初始化' }
restart_gitea() { echo '🔄 正在重启 Gitea ...' systemctl restart gitea echo '✅ 已重启' }
stop_gitea() { echo '⏹️ 正在停止 Gitea ...' systemctl stop gitea echo '✅ 已停止' }
menu() { echo '===== Gitea 管理 =====' echo '1) 安装最新 Gitea（会自动卸载旧版）' echo '2) 卸载 Gitea' echo '3) 重启 Gitea' echo '4) 停止 Gitea' echo '======================' read -p '请选择操作: ' choice
case $choice in 1) install_gitea ;; 2) uninstall_gitea ;; 3) restart_gitea ;; 4) stop_gitea ;; *) echo '无效选择' ;; esac }
menu ```。

## 获取链接
```
const links = document.getElementsByTagName('a');

// 遍历所有链接并查找匹配 Hugging Face blob 地址
for (const link of links) {
  const href = link.href;
  // 匹配 datasets 仓库 blob 链接
  const urlRegex = /^https:\/\/huggingface\.co\/datasets\/[^/]+\/[^/]+\/blob\/[^/]+\/.+$/;
  if (urlRegex.test(href)) {
    // 替换 blob → resolve
    const realUrl = href.replace('/blob/', '/resolve/');
    console.log('直链: ' + realUrl);
  }
}
```

## 执行下载

```
# -*- coding: utf-8 -*-
'''
auto_paste_two_options.py
两个选项：
1) 开始：进入坐标获取界面 → F5 保存坐标后自动开始循环
0) 退出

循环逻辑：
- 从 TXT 每行读取
- 点击输入框 → 粘贴 → 回车(或点击按钮)
- 间隔 N 秒继续
'''

import os, sys, json, time, subprocess

# ===== 依赖自动安装 =====
def ensure_packages():
    for p in ['pyautogui', 'keyboard', 'pyperclip']:
        try:
            __import__('pyautogui' if p=='pyautogui' else p)
        except Exception:
            print(f'[安装] 缺少 {p}，正在安装...')
            subprocess.check_call([sys.executable, '-m', 'pip', 'install', p])
ensure_packages()

import pyautogui, keyboard, pyperclip

pyautogui.FAILSAFE = True
pyautogui.PAUSE = 0.03

CONFIG_FILE = 'auto_paste_config.json'
STATE_FILE  = 'auto_paste_state.json'

# ===== 这里按需改默认值 =====
DEFAULT_CONFIG = {
    'txt_file': r'c:\Users\Puck\Desktop\sid.txt',   # ← 改成你的 txt 路径
    'coords': {'click_target': None, 'submit_btn': None},
    'interval_sec': 180,                  # 间隔秒（3分钟）
    'clear_before_paste': True,           # 粘贴前 Ctrl+A 清空
    'press_enter_after_paste': True       # True=回车提交；False=点击 submit_btn
}

# ========== 工具函数 ==========
def load_json(path, default=None):
    if os.path.exists(path):
        try:
            with open(path, 'r', encoding='utf-8') as f:
                return json.load(f)
        except Exception:
            pass
    return default

def save_json(path, data):
    with open(path, 'w', encoding='utf-8') as f:
        json.dump(data, f, ensure_ascii=False, indent=2)

def get_conf():
    conf = load_json(CONFIG_FILE, None)
    if conf is None:
        conf = DEFAULT_CONFIG.copy()
        save_json(CONFIG_FILE, conf)
    else:
        # 补齐字段
        for k, v in DEFAULT_CONFIG.items():
            if k not in conf: conf[k] = v
        if 'coords' not in conf or not isinstance(conf['coords'], dict):
            conf['coords'] = {'click_target': None, 'submit_btn': None}
        conf['coords'].setdefault('click_target', None)
        conf['coords'].setdefault('submit_btn', None)
        save_json(CONFIG_FILE, conf)
    return conf

def click(xy):
    if not xy: return
    x, y = xy
    pyautogui.moveTo(x, y, duration=0.05)
    pyautogui.click()

def paste_text(text, clear_before=True):
    if clear_before:
        pyautogui.hotkey('ctrl', 'a'); time.sleep(0.05)
    pyperclip.copy(text); time.sleep(0.05)
    pyautogui.hotkey('ctrl', 'v')

def press_enter():
    pyautogui.press('enter')

def human_time(sec):
    m, s = divmod(int(sec), 60)
    h, m = divmod(m, 60)
    if h: return f'{h}小时{m}分{s}秒'
    if m: return f'{m}分{s}秒'
    return f'{s}秒'

def countdown(total_sec):
    start = time.time()
    paused = False
